#!/usr/bin/env node
/**
 * Add image fields to characters.json and weapons.json
 * References the placeholder images generated by generate-placeholders.js
 */

const fs = require("fs");
const path = require("path");

const ROOT = path.resolve(__dirname, "..");
const DATA_DIR = path.join(ROOT, "data");

/**
 * Add image field to items in a JSON file
 */
function addImageFields(filename, type) {
  const filePath = path.join(DATA_DIR, filename);
  const data = JSON.parse(fs.readFileSync(filePath, "utf-8"));

  let updated = 0;

  for (const item of data) {
    if (!item.image) {
      item.image = `/images/${type}/${item.id}.webp`;
      updated++;
    }
  }

  if (updated > 0) {
    fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + "\n");
    console.log(`✅ ${filename}: Added image field to ${updated} items`);
  } else {
    console.log(`ℹ️  ${filename}: All items already have image field`);
  }
}

console.log("🖼️  Adding image fields to data files...\n");

addImageFields("characters.json", "characters");
addImageFields("weapons.json", "weapons");

console.log("\n✅ Done!");
